import{B as e,Q as t,s as n,z as r}from"./chunks/framework.BtoUXlJN.js";var i=JSON.parse(`{"title":"Player Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"guide/player-dashboard.md","filePath":"guide/player-dashboard.md"}`),a={name:`guide/player-dashboard.md`};function o(n,i,a,o,s,c){return t(),r(`div`,null,[...i[0]||=[e(`<h1 id="player-dashboard" tabindex="-1">Player Dashboard <a class="header-anchor" href="#player-dashboard" aria-label="Permalink to &quot;Player Dashboard&quot;">​</a></h1><p>Welcome to the Player Dashboard guide. This documentation is automatically generated from the latest game features.</p><h2 id="effective-stats-and-status-cards" tabindex="-1">Effective Stats and Status Cards <a class="header-anchor" href="#effective-stats-and-status-cards" aria-label="Permalink to &quot;Effective Stats and Status Cards&quot;">​</a></h2><p>The Effective Stats section shows real-time HP, Stamina, Momentum, and Hand Size after applying all active modifiers — campaign bonuses/penalties, injuries, bumps, and Status Cards. Hover over any stat for a full breakdown. Active Status Cards appear as colour-coded badges: green for positive, red for negative.</p><p><img src="/atw-rpg/docs/screenshots/player-effective-stats.png" alt="Effective Stats and Status Cards"></p><hr><h2 id="season-summary" tabindex="-1">Season Summary <a class="header-anchor" href="#season-summary" aria-label="Permalink to &quot;Season Summary&quot;">​</a></h2><p>The Season Summary component provides a snapshot of your wrestler&#39;s performance during the currently active season, including their win-loss record, fan growth progress, and any championships or accolades earned.</p><p><img src="/atw-rpg/docs/screenshots/player-season-summary.png" alt="Season Summary"></p><hr><h2 id="inbox-—-event-feed" tabindex="-1">Inbox — Event Feed <a class="header-anchor" href="#inbox-—-event-feed" aria-label="Permalink to &quot;Inbox — Event Feed&quot;">​</a></h2><p>The Inbox surfaces every automated event that affects your wrestlers — championship changes, injury reports, rivalry heat shifts, and achievement unlocks. Filter by event type or wrestler target to focus on what matters most. Unread items are highlighted; select any row to mark it read or act on it.</p><p><img src="/atw-rpg/docs/screenshots/inbox-overview.png" alt="Inbox — Event Feed"></p><hr><h2 id="career-legacy" tabindex="-1">Career Legacy <a class="header-anchor" href="#career-legacy" aria-label="Permalink to &quot;Career Legacy&quot;">​</a></h2><p>Your persistent career progress is tracked at the account level. View your current Legacy Score, Prestige XP, and earned achievement badges directly from your dashboard. These stats persist across seasons and different wrestlers.</p><p><img src="/atw-rpg/docs/screenshots/player-career-legacy.png" alt="Career Legacy"></p><hr><h2 id="medals-achievements" tabindex="-1">Medals &amp; Achievements <a class="header-anchor" href="#medals-achievements" aria-label="Permalink to &quot;Medals &amp; Achievements&quot;">​</a></h2><p>Track your progress toward various career milestones in the Achievements tab. Each achievement awards permanent Prestige XP and a unique medal displayed on your profile.</p><p><img src="/atw-rpg/docs/screenshots/player-achievements.png" alt="Medals &amp; Achievements"></p><hr><h2 id="historical-season-performance" tabindex="-1">Historical Season Performance <a class="header-anchor" href="#historical-season-performance" aria-label="Permalink to &quot;Historical Season Performance&quot;">​</a></h2><p>Review your past glory by switching between seasons. The dashboard stores historical data, allowing you to track your wrestler&#39;s career trajectory and milestones over time.</p><p><img src="/atw-rpg/docs/screenshots/player-season-history.png" alt="Historical Season Performance"></p><hr>`,26)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};